import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Retry、指数退避、Dead Letter Queue 与 Poison Message","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"retry-dlq-poison-message"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/09-retry-dlq-poison-message.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/09-retry-dlq-poison-message.md","lastUpdated":null}'),r={name:"05-backend-data/notes/07-cache-messaging-storage/09-retry-dlq-poison-message.md"};function n(l,a,o,d,h,p){return t(),i("div",null,[...a[0]||(a[0]=[s(`<h1 id="retry、指数退避、dead-letter-queue-与-poison-message" tabindex="-1">Retry、指数退避、Dead Letter Queue 与 Poison Message <a class="header-anchor" href="#retry、指数退避、dead-letter-queue-与-poison-message" aria-label="Permalink to &quot;Retry、指数退避、Dead Letter Queue 与 Poison Message&quot;">​</a></h1><p>重试只适用于暂时失败，并且必须受次数、总时限、容量和幂等约束。DLQ 是隔离与人工/自动修复入口，不是把失败消息移走后不再处理的终点。</p><h2 id="_1-先分类失败" tabindex="-1">1. 先分类失败 <a class="header-anchor" href="#_1-先分类失败" aria-label="Permalink to &quot;1. 先分类失败&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>例子</th><th style="text-align:right;">原样重试</th><th>动作</th></tr></thead><tbody><tr><td>暂时依赖失败</td><td>timeout、503、短锁冲突</td><td style="text-align:right;">是</td><td>有界退避</td></tr><tr><td>限流/过载</td><td>429、consumer 下游饱和</td><td style="text-align:right;">是</td><td>Respect Retry-After/降速</td></tr><tr><td>确定性输入错误</td><td>schema 缺字段、非法枚举</td><td style="text-align:right;">否</td><td>隔离/DLQ</td></tr><tr><td>业务终态冲突</td><td>对象已取消、权限撤销</td><td style="text-align:right;">通常否</td><td>记录终态</td></tr><tr><td>代码 bug</td><td>panic、nil dereference</td><td style="text-align:right;">原样会重复</td><td>停止/发布修复</td></tr><tr><td>未知外部结果</td><td>请求 timeout 但可能执行</td><td style="text-align:right;">先对账</td><td>不盲重试</td></tr></tbody></table><p>分类必须基于稳定错误码/类型，不解析错误文案。5xx 也可能是确定性 bug；4xx 中 408/429 可能可重试。</p><h2 id="_2-重试预算" tabindex="-1">2. 重试预算 <a class="header-anchor" href="#_2-重试预算" aria-label="Permalink to &quot;2. 重试预算&quot;">​</a></h2><p>单条消息的预算包括最大 attempts、elapsed time 和业务 deadline。系统预算还包括全局 retry QPS、并发和队列容量。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>max_attempts = 8</span></span>
<span class="line"><span>max_elapsed = 2 hours</span></span>
<span class="line"><span>per_attempt_timeout = min(10s, remaining_budget)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>达到任一上限进入终态/DLQ。无限重试会阻塞 partition、积压并持续攻击故障依赖。</p><h2 id="_3-指数退避与-jitter" tabindex="-1">3. 指数退避与 jitter <a class="header-anchor" href="#_3-指数退避与-jitter" aria-label="Permalink to &quot;3. 指数退避与 jitter&quot;">​</a></h2><p>基础指数：<code>delay = min(cap, base × 2^attempt)</code>。所有 consumer 同时恢复会同步重试，必须 jitter。</p><p>常见 full jitter：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delay = random(0, min(cap, base × 2^attempt))</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>decorrelated jitter 可基于上次延迟随机增长。选型通过负载仿真，不需要不同服务各自发明。<code>Retry-After</code> 是下游明确提示时的下限/依据，但仍受业务总 deadline。</p><h2 id="_4-重试放在哪里" tabindex="-1">4. 重试放在哪里 <a class="header-anchor" href="#_4-重试放在哪里" aria-label="Permalink to &quot;4. 重试放在哪里&quot;">​</a></h2><h3 id="consumer-内短重试" tabindex="-1">Consumer 内短重试 <a class="header-anchor" href="#consumer-内短重试" aria-label="Permalink to &quot;Consumer 内短重试&quot;">​</a></h3><p>适合几十毫秒瞬态网络错误，次数少。期间 partition/visibility 被占用；长 sleep 会降低吞吐和触发 group timeout。</p><h3 id="延迟-重试-queue-或-topic" tabindex="-1">延迟/重试 Queue 或 Topic <a class="header-anchor" href="#延迟-重试-queue-或-topic" aria-label="Permalink to &quot;延迟/重试 Queue 或 Topic&quot;">​</a></h3><p>失败消息发布到按延迟级别的 retry topic，原 consumer 继续处理后续。需保留原 event ID、attempt、first_failed_at、错误类别。跨 topic 会打乱顺序。</p><h3 id="broker-延迟能力" tabindex="-1">Broker 延迟能力 <a class="header-anchor" href="#broker-延迟能力" aria-label="Permalink to &quot;Broker 延迟能力&quot;">​</a></h3><p>部分工作队列有延迟/TTL/visibility。语义和最大延迟依产品，不把 RabbitMQ 插件、云队列和 Kafka 当同一 API。</p><h3 id="调度数据库" tabindex="-1">调度数据库 <a class="header-anchor" href="#调度数据库" aria-label="Permalink to &quot;调度数据库&quot;">​</a></h3><p>对需取消、优先级、查询状态的长任务，用 job 表 <code>next_attempt_at</code> 和 worker lease 更清晰。Kafka 不原生提供任意单消息延时队列。</p><h2 id="_5-kafka-retry-topic" tabindex="-1">5. Kafka Retry Topic <a class="header-anchor" href="#_5-kafka-retry-topic" aria-label="Permalink to &quot;5. Kafka Retry Topic&quot;">​</a></h2><p>一种结构：<code>orders.events</code> → <code>orders.retry.1m</code> → <code>orders.retry.10m</code> → <code>orders.dlq</code>。转发必须在业务提交/失败分类后可靠进行；若提交原 offset 成功但发 retry 失败会丢。</p><p>可用 Kafka transaction 原子发送 retry 记录和提交 consumed offset（链路都在 Kafka），或先持久化失败 intent/outbox。消息 headers/payload 保留 original topic/partition/offset 仅用于追踪，业务去重仍用 event ID。</p><p>重试 topic 破坏同 key 顺序：后续 v11 正常成功，v10 之后重试到达。consumer 必须使用 aggregate version/幂等，而不能依赖原 partition 顺序。</p><h2 id="_6-poison-message" tabindex="-1">6. Poison Message <a class="header-anchor" href="#_6-poison-message" aria-label="Permalink to &quot;6. Poison Message&quot;">​</a></h2><p>Poison message 在当前代码/数据下每次处理都确定失败，例如不支持 schema、损坏压缩、触发 bug。若一直原地重试，会阻塞 partition 或快速烧 CPU。</p><p>检测：相同 event ID/offset 多次同类失败；解码错误；非重试 error；超过 budget。隔离时保存足够诊断元数据和原始 payload 的安全引用，不在普通日志打印敏感内容。</p><p>一条消息导致进程崩溃时，外层 recovery/隔离必须能识别 offset；但数据反序列化应先限制大小/深度，防止 OOM 在 recovery 前杀进程。</p><h2 id="_7-dead-letter-queue-契约" tabindex="-1">7. Dead Letter Queue 契约 <a class="header-anchor" href="#_7-dead-letter-queue-契约" aria-label="Permalink to &quot;7. Dead Letter Queue 契约&quot;">​</a></h2><p>DLQ envelope：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dlq_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;01JZ...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;original&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;topic&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;orders.v1.events&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;partition&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">7</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;offset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">421</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;event_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;evt_9&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;schema_version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;attempts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;first_failed_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-17T08:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_failed_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-17T09:30:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;category&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;unsupported_schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SCHEMA_99&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;payload_ref&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;s3://restricted-dlq/sha256/...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>DLQ 有 owner、告警、保留、访问控制、加密、修复和 re-drive 流程。payload 可能含 PII；默认只保存加密对象引用/checksum，权限与审计更严。</p><h2 id="_8-dlq-不是成功" tabindex="-1">8. DLQ 不是成功 <a class="header-anchor" href="#_8-dlq-不是成功" aria-label="Permalink to &quot;8. DLQ 不是成功&quot;">​</a></h2><p>进入 DLQ 表示主消费路径绕过了该业务结果。业务看板必须反映缺失投影/任务失败；不能只因 consumer lag 归零就显示健康。</p><p>指标：DLQ rate、oldest age、按 error category、未处置数、re-drive success、再次 DLQ。低频关键支付 DLQ 比高频日志 DLQ 更严重，告警按业务价值。</p><h2 id="_9-re-drive" tabindex="-1">9. Re-drive <a class="header-anchor" href="#_9-re-drive" aria-label="Permalink to &quot;9. Re-drive&quot;">​</a></h2><p>修复 schema/代码/数据后重放：</p><ol><li>选择明确问题类别和时间范围。</li><li>在 staging/影子 consumer 验证修复。</li><li>为 re-drive 建批次 ID、速率和并发上限。</li><li>保持原 event ID，新增 re-drive ID/attempt。</li><li>消费者幂等；已被人工修复的消息不会重复副作用。</li><li>观察下游、失败率，支持暂停。</li><li>成功后记录审计，不立即删除原 DLQ 证据。</li></ol><p>整队一键重放会把旧 bug/容量峰值重新注入生产。</p><h2 id="_10-顺序与阻塞策略" tabindex="-1">10. 顺序与阻塞策略 <a class="header-anchor" href="#_10-顺序与阻塞策略" aria-label="Permalink to &quot;10. 顺序与阻塞策略&quot;">​</a></h2><p>当失败消息 v10 阻塞同订单 v11：</p><ul><li>严格事件序列：暂停该 key/partition，修复 v10，代价是共享 partition 其他 key 受阻。</li><li>每 aggregate parking lot：把该 aggregate 后续消息暂存，其他 key 继续；实现复杂。</li><li>状态快照投影：v11 完整状态可覆盖，v10 隔离并忽略旧版本。</li><li>增量 ledger：不能跳过，必须补齐或从事实重建。</li></ul><p>策略来自事件语义，不是统一“跳过 poison”。</p><h2 id="_11-优雅退避与消费背压" tabindex="-1">11. 优雅退避与消费背压 <a class="header-anchor" href="#_11-优雅退避与消费背压" aria-label="Permalink to &quot;11. 优雅退避与消费背压&quot;">​</a></h2><p>下游整体 503 时，继续 poll→retry topic 会把同样流量复制并增加 broker 写。consumer 应降低/暂停 partitions、减少并发、打开 circuit breaker，并保持 group 心跳的正确客户端方式。</p><p>恢复时缓慢增加并发，避免 retry backlog + 新流量同时冲击。为 retry 和新消息分配公平/优先容量。</p><h2 id="_12-未知结果" tabindex="-1">12. 未知结果 <a class="header-anchor" href="#_12-未知结果" aria-label="Permalink to &quot;12. 未知结果&quot;">​</a></h2><p>支付请求 timeout 可能已扣款，标为 <code>unknown</code>：</p><ol><li>以稳定 idempotency key 查询供应商。</li><li>使用 webhook/对账文件确认。</li><li>在确认未执行后才重试。</li><li>超过业务时间进入人工调查，不把 unknown 当 failed。</li></ol><p>消息重试框架必须允许 unknown 状态，不能只有 success/fail。</p><h2 id="_13-retry-storm" tabindex="-1">13. Retry Storm <a class="header-anchor" href="#_13-retry-storm" aria-label="Permalink to &quot;13. Retry Storm&quot;">​</a></h2><p>故障恢复时百万消息同时到期产生重试风暴。防护：full jitter、全局 token bucket、每 tenant 配额、下游 circuit breaker、retry schedule 分桶、恢复斜坡、最大积压容量。</p><p>多个微服务逐层各重试 3 次会放大为 3^N。选择一个拥有业务上下文的层负责重试，下游客户端只做极少连接级重试。</p><h2 id="_14-应用案例一-搜索索引暂时失败" tabindex="-1">14. 应用案例一：搜索索引暂时失败 <a class="header-anchor" href="#_14-应用案例一-搜索索引暂时失败" aria-label="Permalink to &quot;14. 应用案例一：搜索索引暂时失败&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>OpenSearch 维护期间 30 分钟 503；订单事件 5000/s；搜索允许 2 小时 lag，事件是完整状态快照。</p><h3 id="处理" tabindex="-1">处理 <a class="header-anchor" href="#处理" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>3 次秒级 jitter 后判依赖不可用，打开 circuit breaker。</li><li>pause 消费或转持久 retry topic，不让应用内存堆积。</li><li>retry 记录保留 event ID/version；v11 后到可覆盖 v10。</li><li>恢复后按 20%→50%→100% 速率追赶，监控集群 reject/latency。</li><li>超过 2 小时进入业务降级和告警，不悄悄清 offset。</li></ol><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>恢复期间新+旧写入不超 OpenSearch bulk capacity；最终文档最高 version；consumer lag、retry age 和搜索 freshness 同时可见。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>503 持续 3 小时，系统不无限 retry CPU、不 OOM；搜索 API显示数据更新时间/降级。若直接 DLQ 所有暂时错误，恢复要人工重放且失去自动追赶。</p><h2 id="_15-应用案例二-不支持的-schema" tabindex="-1">15. 应用案例二：不支持的 schema <a class="header-anchor" href="#_15-应用案例二-不支持的-schema" aria-label="Permalink to &quot;15. 应用案例二：不支持的 schema&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>consumer 只支持 v1/v2，却收到 v99；同 partition 后有其他订单。</p><h3 id="处理-1" tabindex="-1">处理 <a class="header-anchor" href="#处理-1" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>解码 envelope 后发现版本不支持，确定性错误不重试。</li><li>把 payload 加密引用和 schema 信息写 DLQ，可靠提交后推进 offset。</li><li>告警 producer/consumer compatibility；按业务决定 partition 是否允许继续。</li><li>发布 v99 支持后，小批 re-drive，保持 event ID。</li></ol><h3 id="验证与失败分支" tabindex="-1">验证与失败分支 <a class="header-anchor" href="#验证与失败分支" aria-label="Permalink to &quot;验证与失败分支&quot;">​</a></h3><p>v99 不形成热循环；DLQ 写失败时不能提交原 offset，否则永久丢。re-drive 重复不会重复业务结果。</p><h2 id="_16-应用案例三-邮件供应商限流" tabindex="-1">16. 应用案例三：邮件供应商限流 <a class="header-anchor" href="#_16-应用案例三-邮件供应商限流" aria-label="Permalink to &quot;16. 应用案例三：邮件供应商限流&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>供应商返回 429 + Retry-After 120 秒；每 tenant 每小时配额不同；邮件有发送截止时间。</p><h3 id="处理-2" tabindex="-1">处理 <a class="header-anchor" href="#处理-2" aria-label="Permalink to &quot;处理&quot;">​</a></h3><ol><li>解析可信 Retry-After，记录 next_attempt_at，不 sleep 持有 consumer lease。</li><li>调度表按 tenant token bucket 和优先级领取。</li><li>deadline 前指数+jitter重试；过期后标 failed-expired，进入业务补偿而非 DLQ 无尽等待。</li><li>供应商 timeout 标 unknown 先对账。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>限流不会让其他 tenant 饿死；高优先事务邮件保留容量；过期状态可查询。</p><h2 id="_17-方案比较" tabindex="-1">17. 方案比较 <a class="header-anchor" href="#_17-方案比较" aria-label="Permalink to &quot;17. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机制</th><th>适合</th><th>风险</th></tr></thead><tbody><tr><td>Consumer 内重试</td><td>极短瞬态</td><td>阻塞 poll/lease</td></tr><tr><td>Retry topic</td><td>大吞吐分级延迟</td><td>乱序、topic 数、转发原子性</td></tr><tr><td>Queue visibility</td><td>工作任务</td><td>旧 worker 并发、需续租</td></tr><tr><td>Job 调度表</td><td>取消/优先级/任意时间</td><td>DB 扫描与锁设计</td></tr><tr><td>DLQ</td><td>确定失败隔离</td><td>变成无人处理墓地</td></tr></tbody></table><h2 id="_18-调试和生产指标" tabindex="-1">18. 调试和生产指标 <a class="header-anchor" href="#_18-调试和生产指标" aria-label="Permalink to &quot;18. 调试和生产指标&quot;">​</a></h2><p>按 error category 记录 attempt、next delay、first/last failure、retry age；观察 retry throughput、scheduled count、DLQ oldest、re-drive batch、circuit state、下游 429/5xx、unknown outcome。</p><p>日志用 event ID/dlq ID 关联，不打印 payload/secret。trace 对每次 attempt 建 link，不把几小时重试做一个不断增长 span。</p><h3 id="容量与保留" tabindex="-1">容量与保留 <a class="header-anchor" href="#容量与保留" aria-label="Permalink to &quot;容量与保留&quot;">​</a></h3><p>重试容量按峰值失败率而非平均估算。若入口 2 万条/s、依赖最长故障 2 小时，理论积压 1.44 亿条；还要计 payload、索引、副本和 re-drive 双流量。容量不足时应在入口背压/暂停非关键生产者，而不是让 broker 磁盘耗尽。</p><p>DLQ 保留必须覆盖发现、修复、审批和重放周期。原 topic 先到期时，DLQ envelope 仍需足够的 schema 和安全 payload 引用才能重建。加密对象引用的生命周期不能短于 DLQ；密钥轮换要保证旧消息可解。</p><p>告警分两级：单条关键资金 poison 立即业务告警；大量同 error code 表示发布/依赖事故。用错误类别聚合，未知类别必须显式出现，不能落入无监控的 <code>other</code>。</p><h3 id="re-drive-回滚" tabindex="-1">Re-drive 回滚 <a class="header-anchor" href="#re-drive-回滚" aria-label="Permalink to &quot;Re-drive 回滚&quot;">​</a></h3><p>re-drive 发布错误时要能按 batch ID 停止，并识别已成功处理的 event。修复代码若再次失败，消息进入新的隔离状态但保留原始失败链；不能覆盖第一次证据。对产生外部副作用的重放先在 dry-run/影子模式计算将要改变的对象集合，再审批执行。</p><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现含短重试、延迟调度、DLQ 和 re-drive 的 consumer。注入 503、429、schema v99、poison panic、DB commit 后崩溃和供应商 unknown。</p><p>验收：确定错误不原样重试；暂时错误有 jitter/总预算；重试不阻塞整个消费；DLQ 写与原 offset 推进不丢；re-drive 限速且幂等；顺序/gap 策略按事件类型区分；retry storm 不超过下游预算；所有 DLQ 有 owner 和 oldest-age 告警。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#consumerconfigs" target="_blank" rel="noreferrer">Apache Kafka consumer configuration</a>（访问日期：2026-07-17）</li><li><a href="https://kafka.apache.org/documentation/#transactions" target="_blank" rel="noreferrer">Apache Kafka transactions</a>（访问日期：2026-07-17）</li><li><a href="https://aws.amazon.com/builders-library/timeouts-retries-and-backoff-with-jitter/" target="_blank" rel="noreferrer">AWS Builders Library: Timeouts, retries and backoff with jitter</a>（访问日期：2026-07-17）</li><li><a href="https://redis.io/docs/latest/develop/data-types/streams/" target="_blank" rel="noreferrer">Redis Streams</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc9110.html#name-retry-after" target="_blank" rel="noreferrer">RFC 9110: Retry-After</a>（访问日期：2026-07-17）</li></ul>`,95)])])}const k=e(r,[["render",n]]);export{u as __pageData,k as default};
